/**
 * Integration smoke for the /rename-preserve delta-detect fix.
 *
 * Drives the BUILT bundle (`dist/prompt.mjs`) against a real temp filesystem
 * — no `vi.mock('node:fs')`. Catches drift between source and the bundled
 * artifact that pure unit tests can't see (e.g., tree-shaking removing the
 * helper, esbuild mangling state-file paths, missing exports in the bundle).
 *
 * If the unit tests at `__tests__/prompt/session-title.test.ts` pass but
 * this file fails, you have a build/packaging bug, not a logic bug.
 *
 * Prerequisite: `cd src/hooks && npm run build` (CI runs this before tests).
 */

import { describe, test, expect, beforeEach, afterEach } from 'vitest';
import { mkdtempSync, existsSync, readFileSync, rmSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join, resolve } from 'node:path';

type DispatchFn = (input: unknown, ctx: unknown) => {
  hookSpecificOutput?: { sessionTitle?: string };
};

const BUNDLE = resolve(__dirname, '../../../dist/prompt.mjs');

describe('integration — sessionTitle delta-detect (built bundle)', () => {
  let dispatch: DispatchFn;
  let tmpProj: string;
  const sessionId = 'integration-smoke-001';

  beforeEach(async () => {
    if (!existsSync(BUNDLE)) {
      throw new Error(
        `Built bundle missing at ${BUNDLE}. Run \`npm run build\` in src/hooks/ first.`,
      );
    }
    // Dynamic import — bundle is ESM, only available after build
    const mod = await import(BUNDLE);
    const fn = mod.hooks?.['prompt/unified-dispatcher'];
    if (typeof fn !== 'function') {
      throw new Error(
        'prompt/unified-dispatcher not exported from bundle.hooks — bundle structure changed',
      );
    }
    dispatch = fn as DispatchFn;
    tmpProj = mkdtempSync(join(tmpdir(), 'rename-fix-integration-'));
  });

  afterEach(() => {
    if (tmpProj) rmSync(tmpProj, { recursive: true, force: true });
  });

  function input(prompt: string) {
    return {
      hook_event: 'UserPromptSubmit',
      tool_name: 'UserPromptSubmit',
      session_id: sessionId,
      project_dir: tmpProj,
      tool_input: {},
      prompt,
    };
  }

  function ctx(branch: string, isWorktree = false) {
    return {
      branch,
      isWorktree,
      sessionId,
      projectDir: tmpProj,
      log: () => {},
    };
  }

  test('full lifecycle: first → same → thrash → still held (branch pin)', () => {
    const sessionDir = join(tmpProj, '.claude', 'memory', 'sessions', sessionId);
    const stateFile = join(sessionDir, 'last-session-title.txt');
    const branchPinFile = join(sessionDir, 'session-branch.txt');

    // Turn 1: first turn (no state file) → emit + write title + pin branch
    const r1 = dispatch(input('hello'), ctx('feature-auth'));
    expect(r1.hookSpecificOutput?.sessionTitle).toBe('feature-auth');
    expect(existsSync(stateFile)).toBe(true);
    expect(readFileSync(stateFile, 'utf8').trim()).toBe('feature-auth');
    // The branch was pinned to the first-seen value.
    expect(existsSync(branchPinFile)).toBe(true);
    expect(readFileSync(branchPinFile, 'utf8').trim()).toBe('feature-auth');

    // Turn 2: same branch → OMIT title (the /rename-preserves bit)
    const r2 = dispatch(input('still working'), ctx('feature-auth'));
    expect(r2.hookSpecificOutput?.sessionTitle).toBeUndefined();

    // Turn 3: another session flipped the shared working-tree branch to
    // 'feature-pay'. THIS session pinned 'feature-auth', so the title is held
    // (NOT re-emitted) and the user's /rename survives. This is the fix.
    const r3 = dispatch(input('thrashed by another session'), ctx('feature-pay'));
    expect(r3.hookSpecificOutput?.sessionTitle).toBeUndefined();
    expect(readFileSync(stateFile, 'utf8').trim()).toBe('feature-auth');
    expect(readFileSync(branchPinFile, 'utf8').trim()).toBe('feature-auth');

    // Turn 4: still the thrashed branch → still held
    const r4 = dispatch(input('more'), ctx('feature-pay'));
    expect(r4.hookSpecificOutput?.sessionTitle).toBeUndefined();
  });

  test('worktree suffix participates in delta-detect', () => {
    // Initial turn on a regular checkout
    const r1 = dispatch(input('first'), ctx('feat/x', false));
    expect(r1.hookSpecificOutput?.sessionTitle).toBe('feat/x');

    // Same branch, but now in a worktree → suffix changes → emit
    const r2 = dispatch(input('moved to worktree'), ctx('feat/x', true));
    expect(r2.hookSpecificOutput?.sessionTitle).toBe('feat/x · wt');

    // Same branch + worktree again → no delta
    const r3 = dispatch(input('still here'), ctx('feat/x', true));
    expect(r3.hookSpecificOutput?.sessionTitle).toBeUndefined();
  });

  test('parallel sessions on same branch keep independent state', () => {
    const sessionA = 'session-a';
    const sessionB = 'session-b';

    const inputA = { ...input('a1'), session_id: sessionA };
    const inputB = { ...input('b1'), session_id: sessionB };
    const ctxA = { ...ctx('shared-branch'), sessionId: sessionA };
    const ctxB = { ...ctx('shared-branch'), sessionId: sessionB };

    // Both first turns emit independently
    expect(dispatch(inputA, ctxA).hookSpecificOutput?.sessionTitle).toBe('shared-branch');
    expect(dispatch(inputB, ctxB).hookSpecificOutput?.sessionTitle).toBe('shared-branch');

    // Both second turns omit independently
    const inputA2 = { ...input('a2'), session_id: sessionA };
    const inputB2 = { ...input('b2'), session_id: sessionB };
    expect(dispatch(inputA2, ctxA).hookSpecificOutput?.sessionTitle).toBeUndefined();
    expect(dispatch(inputB2, ctxB).hookSpecificOutput?.sessionTitle).toBeUndefined();

    // Each session has its own state file
    const fileA = join(
      tmpProj,
      '.claude',
      'memory',
      'sessions',
      sessionA,
      'last-session-title.txt',
    );
    const fileB = join(
      tmpProj,
      '.claude',
      'memory',
      'sessions',
      sessionB,
      'last-session-title.txt',
    );
    expect(existsSync(fileA)).toBe(true);
    expect(existsSync(fileB)).toBe(true);
  });
});
